// Retient les DERNIÈRES mesures réelles de chaque équipement (payload MQTT).
let p = msg.payload;
if (typeof p === 'string') { try { p = JSON.parse(p); } catch (e) { return null; } }
if (!p || typeof p !== 'object') return null;

// Aplatit le payload (measurements imbriqués inclus)
const flat = {};
(function walk(o) {
  for (const k in o) {
    const v = o[k];
    if (v && typeof v === 'object' && !Array.isArray(v)) walk(v);
    else if (typeof v === 'number' || typeof v === 'boolean') flat[String(k).toLowerCase()] = v;
    else if (typeof v === 'string' && v !== '' && !isNaN(parseFloat(v))) flat[String(k).toLowerCase()] = parseFloat(v);
  }
})(p);

const devRaw = String(
  p.device_id || p.sub_equipment_id || p.equipment || p.equipment_name ||
  p.device_name || (msg.topic || '').split('/').slice(-2).join('_') || ''
).toLowerCase().replace(/[^a-z0-9]+/g, '_');
if (!devRaw) return null;

const pick = (re) => { for (const k in flat) { if (re.test(k)) return flat[k]; } return undefined; };

const devices = flow.get('sld_devices') || {};
const d = devices[devRaw] || {};
const kw   = pick(/active_power|power_kw|^kw$/);
const vll  = pick(/voltage_l1l2|voltage_l2l3|voltage_l3l1|voltage_ll/);
const vln  = pick(/voltage_l1n|voltage_v1|v_l1n|^voltage$/);
const pf   = pick(/power_factor|^pf$/);
const hz   = pick(/frequency/);
const amp  = pick(/current_l1|current_i1|current_a|^current$/);
const kvar = pick(/reactive_power|kvar/);
const brk  = pick(/breaker/);
if (kw   !== undefined) d.kw = kw;
if (vll  !== undefined) d.vll = vll;
if (vln  !== undefined) d.vln = vln;
if (pf   !== undefined) d.pf = pf;
if (hz   !== undefined) d.hz = hz;
if (amp  !== undefined) d.a = amp;
if (kvar !== undefined) d.kvar = kvar;
if (brk  !== undefined) d.brk = (brk === true || brk === 1);
d.ts = Date.now();
devices[devRaw] = d;
flow.set('sld_devices', devices);
return null;

// Construit le JSON attendu par sld.html (applyUpdate) UNIQUEMENT à partir
// des mesures réelles collectées. Si rien n'est reçu → on n'envoie rien.
const devices = flow.get('sld_devices') || {};
const FRESH_MS = 30000;
const entries = Object.entries(devices).filter(([, d]) => Date.now() - d.ts < FRESH_MS);
if (!entries.length) return null;

const find = (re) => { const e = entries.find(([k]) => re.test(k)); return e ? e[1] : null; };

// Mapping équipements réels Al Youssoufia -> composants du SLD
const bw  = find(/extr.*bw|bucket/);            // Bucket Wheel Excavator
const cv1 = find(/extr.*cv|extr.*conveyor/);    // Conveyor C1 (Extraction)
const cv7 = find(/strg.*cv|cv7|conveyor.*out/); // Conveyor C1 Output (Storage)
const sp  = find(/flot.*sp|slurry/);            // Slurry Pump
const wpa = find(/wash.*(wpa|pump)/);           // Washing Pump A
const ac  = find(/util.*ac|compress/);          // Air Compressor
const ag  = find(/_ag\d|_ag_|agitat/);          // Flotation Cell Agitator 1

const elec = entries.map(([, d]) => d).filter((d) => d.kw !== undefined);
const avg = (xs) => (xs.length ? xs.reduce((s, v) => s + v, 0) / xs.length : null);
const pfs = elec.map((d) => d.pf).filter((v) => v != null);
const hzs = entries.map(([, d]) => d.hz).filter((v) => v != null);
const totKw = elec.reduce((s, d) => s + (d.kw || 0), 0);
const totKvar = entries.reduce((s, [, d]) => s + (d.kvar || 0), 0);

// Tension bus principal : phase-phase réelle si dispo, sinon L-N x racine(3)
const vlls = elec.map((d) => d.vll).filter((v) => v != null);
const vlns = elec.map((d) => d.vln).filter((v) => v != null);
const vmain = vlls.length ? avg(vlls) : vlns.length ? avg(vlns) * 1.7320508 : 400;
const freq = avg(hzs) != null ? avg(hzs) : 50;
const pf = avg(pfs) != null ? avg(pfs) : 0.9;

const ampOf = (d) => (d ? (d.a != null ? d.a : d.kw ? (d.kw * 1000) / (vmain * 1.7320508 * (d.pf || 0.9)) : 0) : 0);
const eqOf = (d) => (d ? {
  on: (d.kw || 0) > 0.5 && d.brk !== false,
  fault: d.brk === false,
  voltage: +vmain.toFixed(1),
  current: +ampOf(d).toFixed(1),
  power_kw: +(d.kw || 0).toFixed(1),
  power_factor: d.pf != null ? +d.pf.toFixed(3) : undefined,
} : undefined);

// Transformateurs : on ne pilote QUE ceux mappés à un vrai power meter
const transformers = {};
[['tr-01', bw], ['tr-02', cv1], ['tr-03', cv7], ['tr-04', sp], ['tr-05', wpa], ['tr-06', ac], ['tr-07', ag]]
  .forEach(([id, d]) => {
    if (d && d.kw !== undefined) transformers[id] = {
      current: +ampOf(d).toFixed(1),
      on: d.brk !== false && (d.kw || 0) > 0.1,
    };
  });

const zoneKw = (ds) => ds.filter(Boolean).reduce((s, d) => s + (d.kw || 0), 0);
const pct = (kw, nom) => Math.max(2, Math.min(100, (kw / nom) * 100));

msg.payload = {
  buses: { main: +vmain.toFixed(1), hv: +((vmain / 400) * 20).toFixed(2), freq: +freq.toFixed(2) },
  power: { active: +totKw.toFixed(1), reactive: +totKvar.toFixed(1), pf: +pf.toFixed(3) },
  loads: {
    left:   +pct(zoneKw([bw, cv1]), 400).toFixed(0),   // Extraction
    centre: +pct(zoneKw([sp, ag, wpa]), 300).toFixed(0), // Flotation + Washing
    right:  +pct(zoneKw([ac, cv7]), 150).toFixed(0),   // Utilities + Storage
    tie:    +pct(totKw, 900).toFixed(0),
  },
  transformers,
  equipment: {
    motor_m1:     eqOf(bw),
    conveyor_cv1: eqOf(cv1),
    conveyor_cv2: eqOf(cv7),
    pump_p1:      eqOf(sp),
    motor_m2:     eqOf(wpa),
    feeder_f1:    eqOf(ac),
    thermo_tp1:   eqOf(ag),
    cap_bank_cap1: {
      on: totKvar > 0 || totKw > 0,
      fault: false,
      kvar: +totKvar.toFixed(1),
      voltage: +vmain.toFixed(1),
      pf_correction: +pf.toFixed(2),
    },
  },
};
return msg;
